import { HORIZONTAL_ALIGN, LEFT_ALIGN, RIGHT_ALIGN, VERTICAL_ALIGN } from "../../core/align-constants";
import { d3_select } from "../../core/d3-constants";
import { axis } from "../../core/main-zc-init";
import { RadialAxisParser } from "./parser/radialaxis-parser";

axis.radial = function () {
    var scaleObj, chartObj, radius, axisObj,
        tickFormat, tickValues, tickRotation = 0,
        axisType, newAxisParser;

    //TODO: Move to class structure for more organized code
    function radial(g) {
        g.each(function (data, index) {
            var g = d3_select(this);

            let ticks = tickValues || (scaleObj.ticks ? scaleObj.ticks() : scaleObj.domain()),
                range = scaleObj.range(),
                yaxis_data = chartObj.systemConf.chart.axes.yaxis[0],
                orient = yaxis_data.orient || RIGHT_ALIGN,
                align = [LEFT_ALIGN, RIGHT_ALIGN].includes(orient) ? VERTICAL_ALIGN : HORIZONTAL_ALIGN,
                parserConf = chartObj.viewFlow?.axes[align][0]?.conf || {};

            let dependencies = {
                type: axisType,
                container: g,
                renderer: radial,
                chart: chartObj,
                axis: axisObj,
                config: axisObj.Ticks.axis,
                data, ticks, range,
                customOperator: {
                    'radial': {
                        extender: parserConf.markExtender,
                        parser: parserConf.markParser
                    }
                }
            };

            let radialParser = newAxisParser = new RadialAxisParser(dependencies);
            radialParser.render();
            return radialParser;
        });
    }

    radial.axis = function (_) {
        return arguments.length ? (axisObj = _, radial) : axisObj;  //TODO: calculate axisObj inside radialaxis instead of axisComponent
    }
    radial.scale = function (_) {
        return arguments.length ? (scaleObj = _, radial) : scaleObj;
    };
    radial.chart = function (_) {
        return arguments.length ? (chartObj = _, radial) : chartObj;
    };
    radial.radius = function (_) {
        return arguments.length ? (radius = _, radial) : radius;
    };
    radial.tickValues = function (_) {
        return arguments.length ? (tickValues = _, radial) : tickValues;
    };
    radial.tickFormat = function (_) {
        return arguments.length ? (tickFormat = _, radial) : tickFormat;
    };
    radial.tickRotation = function (_) {
        return arguments.length ? (tickRotation = _, radial) : tickRotation;
    };
    radial.type = function (_) {
        return arguments.length ? (axisType = _, radial) : axisType;
    }
    radial.parser = function (_) {
        return arguments.length ? (newAxisParser = _, radial) : newAxisParser;
    }

    return radial;
}